it('POST /products should fail with invalid name', async () => {
  const invalidProduct = { name: 'ab', price: 100, stock: 5 };
  const response = await request(app.getHttpServer())
    .post('/products')
    .send(invalidProduct)
    .expect(400);
  expect(response.body.message).toContain('name');
});
